import React, { useRef, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useToast } from '../../context/ToastContext';

const Logo = () => (
  <div style={{display:'flex',alignItems:'center',gap:12,justifyContent:'center',marginBottom:24}}>
    <div style={{width:42,height:42,background:'linear-gradient(135deg,#6366f1,#8b5cf6)',borderRadius:12,display:'flex',alignItems:'center',justifyContent:'center',boxShadow:'0 6px 20px rgba(99,102,241,.5)'}}>
      <span style={{color:'#fff',fontFamily:'var(--ff-h)',fontWeight:800,fontSize:21}}>D</span>
    </div>
    <span style={{fontFamily:'var(--ff-h)',fontWeight:800,fontSize:22,letterSpacing:'-0.03em'}}>DeLaxiY</span>
  </div>
);

export default function AuthModal({ mode, onClose, onSwitch }) {
  const { login, register, loading } = useAuth();
  const { add }  = useToast();
  const navigate = useNavigate();

  // Uncontrolled refs — never causes re-render while typing
  const nameRef  = useRef(null);
  const emailRef = useRef(null);
  const pwRef    = useRef(null);
  const cfmRef   = useRef(null);

  // Only UI state — never causes input re-mount
  const [errs,  setErrs]  = useState({});
  const [show,  setShow]  = useState(false);
  const [showC, setShowC] = useState(false);
  const [pwStr, setPwStr] = useState(0);

  // Validators
  const vName  = v => !v.trim() ? 'Please fill the field' : v.trim().length < 2 ? 'Min 2 characters' : '';
  const vEmail = v => !v.trim() ? 'Please fill the field' : !/^[^@]+@[^@]+\.[^@]+$/.test(v.trim()) ? 'Invalid email address' : '';
  const vPw    = v => !v ? 'Please fill the field' : v.length < 6 ? 'Minimum 6 characters' : '';
  const vCfm   = (v, pw) => !v ? 'Please fill the field' : v !== pw ? 'Passwords do not match' : '';

  // Submit — validates all at once
  async function submit(e) {
    e.preventDefault();
    const name  = nameRef.current?.value  || '';
    const email = emailRef.current?.value || '';
    const pw    = pwRef.current?.value    || '';
    const cfm   = cfmRef.current?.value   || '';
    const ev = {};
    if (mode === 'register') { const n = vName(name);   if (n) ev.name     = n; }
    const em = vEmail(email);                            if (em) ev.email   = em;
    const pe = vPw(pw);                                  if (pe) ev.password= pe;
    if (mode === 'register') { const c = vCfm(cfm, pw); if (c) ev.confirm  = c; }
    if (Object.keys(ev).length) { setErrs(ev); return; }
    setErrs({});
    try {
      if (mode === 'login') await login(email, pw);
      else                  await register(name, email, pw);
      add(mode === 'login' ? '🎉 Welcome back!' : '🚀 Account created!', 'success');
      onClose();
      navigate('/dashboard');
    } catch(err) { setErrs({ _: err.message }); }
  }

  // Strength bar
  const sColor = ['transparent','#f43f5e','#f59e0b','#06b6d4','#10b981'][pwStr];
  const sLabel = ['','Weak','Fair','Good','Strong'][pwStr];

  // Base input style — static, never changes during typing
  const inputStyle = (key) => ({
    background: '#ffffff',
    border: `1.5px solid ${errs[key] ? '#f43f5e' : '#cbd5e1'}`,
    borderRadius: '10px',
    padding: '11px 15px',
    color: '#1e293b',
    fontFamily: 'inherit',
    fontSize: '14px',
    width: '100%',
    outline: 'none',
    boxSizing: 'border-box',
    transition: 'border-color .15s',
  });

  // Field wrapper
  const F = ({ id, label, err, children }) => (
    <div style={{display:'flex',flexDirection:'column',gap:5}}>
      <label htmlFor={id} style={{fontSize:'11px',fontWeight:700,color:'#64748b',textTransform:'uppercase',letterSpacing:'.05em'}}>
        {label}
      </label>
      {children}
      {err && (
        <span style={{fontSize:'12px',color:'#f43f5e',display:'flex',alignItems:'center',gap:4,fontWeight:500}}>
          <span style={{fontSize:9}}>●</span> {err}
        </span>
      )}
    </div>
  );

  return (
    <div className="overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal modal-sm scale-in" onClick={e => e.stopPropagation()}>
        <div style={{height:4,background:'linear-gradient(90deg,#6366f1,#8b5cf6)',borderRadius:'20px 20px 0 0'}}/>
        <div style={{padding:'30px 32px 24px'}}>
          <Logo />

          <div style={{textAlign:'center',marginBottom:22}}>
            <h2 style={{fontSize:20,marginBottom:5,color:'#1e293b'}}>
              {mode === 'login' ? 'Welcome back' : 'Create account'}
            </h2>
            <p style={{fontSize:13,color:'#64748b'}}>
              {mode === 'login' ? 'Sign in to your DeLaxiY account' : 'Start managing orders and dashboards'}
            </p>
          </div>

          {errs._ && (
            <div style={{background:'#fef2f2',border:'1px solid #fecaca',borderRadius:'10px',padding:'10px 14px',color:'#f43f5e',fontSize:13,marginBottom:14,display:'flex',alignItems:'center',gap:8}}>
              <span>✕</span> {errs._}
            </div>
          )}

          <form onSubmit={submit} style={{display:'flex',flexDirection:'column',gap:16}} noValidate>

            {mode === 'register' && (
              <F id="am-name" label="Full Name" err={errs.name}>
                <input
                  id="am-name" ref={nameRef}
                  type="text" name="fullname"
                  placeholder="Enter your full name"
                  defaultValue=""
                  autoComplete="name"
                  style={inputStyle('name')}
                  onFocus={e => e.target.style.borderColor = '#6366f1'}
                  onBlur={e => {
                    e.target.style.borderColor = '#cbd5e1';
                    if (e.target.value.length > 0) {
                      setErrs(p => ({...p, name: vName(e.target.value)}));
                    }
                  }}
                  onChange={e => {
                    if (errs.name) setErrs(p => ({...p, name: vName(e.target.value)}));
                  }}
                />
              </F>
            )}

            <F id="am-email" label="Email Address" err={errs.email}>
              <input
                id="am-email" ref={emailRef}
                type="text" name="email"
                placeholder="you@example.com"
                defaultValue=""
                autoComplete="email"
                style={inputStyle('email')}
                onFocus={e => e.target.style.borderColor = '#6366f1'}
                onBlur={e => {
                  e.target.style.borderColor = '#cbd5e1';
                  if (e.target.value.length > 0) {
                    setErrs(p => ({...p, email: vEmail(e.target.value)}));
                  }
                }}
                onChange={e => {
                  if (errs.email) setErrs(p => ({...p, email: vEmail(e.target.value)}));
                }}
              />
            </F>

            <F id="am-pwd" label="Password" err={errs.password}>
              <div style={{position:'relative'}}>
                <input
                  id="am-pwd" ref={pwRef}
                  type={show ? 'text' : 'password'}
                  name="password"
                  placeholder="Minimum 6 characters"
                  defaultValue=""
                  autoComplete={mode === 'login' ? 'current-password' : 'new-password'}
                  style={{...inputStyle('password'), paddingRight:44}}
                  onFocus={e => e.target.style.borderColor = '#6366f1'}
                  onBlur={e => {
                    e.target.style.borderColor = '#cbd5e1';
                    if (e.target.value.length > 0) {
                      setErrs(p => ({...p, password: vPw(e.target.value)}));
                    }
                  }}
                  onChange={e => {
                    const v = e.target.value;
                    const s = !v ? 0 : v.length < 6 ? 1 : v.length < 10 ? 2
                      : /[A-Z]/.test(v) && /[0-9]/.test(v) ? 4 : 3;
                    setPwStr(s);
                    if (errs.password) setErrs(p => ({...p, password: vPw(v)}));
                    if (cfmRef.current?.value) {
                      setErrs(p => ({...p, confirm: vCfm(cfmRef.current.value, v)}));
                    }
                  }}
                />
                <button type="button" onClick={() => setShow(s => !s)}
                  style={{position:'absolute',right:12,top:'50%',transform:'translateY(-50%)',background:'none',border:'none',color:'#94a3b8',cursor:'pointer',fontSize:15,padding:2,lineHeight:1}}>
                  {show ? '🙈' : '👁'}
                </button>
              </div>
              {mode === 'register' && pwStr > 0 && (
                <div style={{marginTop:5}}>
                  <div style={{display:'flex',gap:4}}>
                    {[1,2,3,4].map(i => (
                      <div key={i} style={{flex:1,height:3,borderRadius:99,background:i<=pwStr?sColor:'#e2e8f0',transition:'background .3s'}}/>
                    ))}
                  </div>
                  <span style={{fontSize:11,color:sColor,fontWeight:600,marginTop:3,display:'block'}}>{sLabel}</span>
                </div>
              )}
            </F>

            {mode === 'register' && (
              <F id="am-conf" label="Confirm Password" err={errs.confirm}>
                <div style={{position:'relative'}}>
                  <input
                    id="am-conf" ref={cfmRef}
                    type={showC ? 'text' : 'password'}
                    name="confirmPassword"
                    placeholder="Repeat your password"
                    defaultValue=""
                    autoComplete="new-password"
                    style={{...inputStyle('confirm'), paddingRight:44}}
                    onFocus={e => e.target.style.borderColor = '#6366f1'}
                    onBlur={e => {
                      e.target.style.borderColor = '#cbd5e1';
                      if (e.target.value.length > 0) {
                        setErrs(p => ({...p, confirm: vCfm(e.target.value, pwRef.current?.value||'')}));
                      }
                    }}
                    onChange={e => {
                      if (errs.confirm) {
                        setErrs(p => ({...p, confirm: vCfm(e.target.value, pwRef.current?.value||'')}));
                      }
                    }}
                  />
                  <button type="button" onClick={() => setShowC(s => !s)}
                    style={{position:'absolute',right:12,top:'50%',transform:'translateY(-50%)',background:'none',border:'none',color:'#94a3b8',cursor:'pointer',fontSize:15,padding:2,lineHeight:1}}>
                    {showC ? '🙈' : '👁'}
                  </button>
                </div>
              </F>
            )}

            <button type="submit" disabled={loading}
              style={{
                display:'flex',alignItems:'center',justifyContent:'center',gap:8,
                width:'100%',padding:'13px',marginTop:2,
                fontSize:15,fontWeight:700,fontFamily:'inherit',
                background:'linear-gradient(135deg,#6366f1,#8b5cf6)',
                color:'#fff',border:'none',borderRadius:'10px',
                cursor:loading?'not-allowed':'pointer',
                boxShadow:'0 4px 16px rgba(99,102,241,.4)',
                opacity:loading?.7:1,transition:'opacity .2s',
              }}>
              {loading
                ? <><span className="spinner" style={{borderTopColor:'#fff',width:14,height:14}}/>{mode==='login'?' Signing in…':' Creating account…'}</>
                : mode === 'login' ? '→ Sign In' : '→ Create Account'
              }
            </button>
          </form>

          <div style={{textAlign:'center',marginTop:18,fontSize:13,color:'#64748b'}}>
            {mode === 'login'
              ? <>Don't have an account?{' '}<button type="button" onClick={() => onSwitch('register')} style={{background:'none',border:'none',color:'#6366f1',cursor:'pointer',fontWeight:700,fontSize:13}}>Register free</button></>
              : <>Already have an account?{' '}<button type="button" onClick={() => onSwitch('login')} style={{background:'none',border:'none',color:'#6366f1',cursor:'pointer',fontWeight:700,fontSize:13}}>Sign in</button></>
            }
          </div>
        </div>
      </div>
    </div>
  );
}
